-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH eqpmnt_pool_max AS (
  SELECT
    EQPMNT_ID,
    EQPMNT_POOL_ID,
    EQPMNT_POOL_ASGNMN_ID,
    MAX(EQPMNT_POOL_ASGNMN_ID) OVER (PARTITION BY EQPMNT_ID) AS MAX_EQPMNT_POOL_ASGNMN_ID
  FROM {{ source('mock_sources', 'EQPMNT_POOL_ASGNMN') }}
)

SELECT
  A.EQPMNT_ID,
  FP.EQPMNT_POOL_ID,
  F.FLEET_NM,
  FSC.FLEET_SBGRP_CTGRY_NM,
  FSC.PARTY_NM,
  F.FLEET_ID,
  TEC.TARGET_EQPMT_CTGRY_NM,
  TP.PRDCT_NM
FROM eqpmnt_pool_max A
LEFT JOIN {{ source('mock_sources', 'EQPMV_FLEET_POOL') }} FP
  ON FP.EQPMNT_POOL_ID = A.EQPMNT_POOL_ID
LEFT JOIN {{ source('mock_sources', 'EQPMV_FLEET_SBGRP') }} FS
  ON FP.FLEET_SBGRP_ID = FS.FLEET_SBGRP_ID
LEFT JOIN {{ source('mock_sources', 'EQPMV_FLEET_SBGRP_CTGRY') }} FSC
  ON FS.FLEET_SBGRP_CTGRY_ID = FSC.FLEET_SBGRP_CTGRY_ID
LEFT JOIN {{ source('mock_sources', 'EQPMV_FLEET') }} F
  ON FP.FLEET_ID = F.FLEET_ID
LEFT JOIN {{ source('mock_sources', 'EQPMV_FLEET_EQPMT_CTGRY') }} FEC
  ON F.FLEET_ID = FEC.FLEET_ID
LEFT JOIN {{ source('mock_sources', 'EQPMV_TARGET_EQPMT_CTGRY') }} TEC
  ON FEC.TARGET_EQPMT_CTGRY_ID = TEC.TARGET_EQPMT_CTGRY_ID
LEFT JOIN {{ source('mock_sources', 'EQPMV_TARGET_PRDCT') }} TP
  ON TEC.TARGET_PRDCT_ID = TP.TARGET_PRDCT_ID
WHERE A.EQPMNT_POOL_ASGNMN_ID = A.MAX_EQPMNT_POOL_ASGNMN_ID
